from fastapi import FastAPI, HTTPException, Header, Depends
from typing import Optional
import secrets

app = FastAPI()

users = {}
next_user_id = 1
tokens = {}
resource_types = {}
next_resource_ids = {}
moderators = set()
admins = set()

def get_current_user(authorization: Optional[str] = Header(None)):
    if not authorization:
        raise HTTPException(status_code=401, detail="Missing auth token")
    token = authorization.replace("Bearer ", "")
    if token not in tokens:
        raise HTTPException(status_code=401, detail="Invalid token")
    return tokens[token]

@app.post("/signup")
def signup(username: str, password: str):
    global next_user_id
    for u in users.values():
        if u["username"] == username:
            raise HTTPException(status_code=400, detail="Username taken")
    user_id = next_user_id
    next_user_id += 1
    users[user_id] = {"id": user_id, "username": username, "password": password}
    return {"id": user_id, "username": username}

@app.post("/login")
def login(username: str, password: str):
    for u in users.values():
        if u["username"] == username and u["password"] == password:
            token = secrets.token_hex(16)
            tokens[token] = u["id"]
            return {"token": token}
    raise HTTPException(status_code=401, detail="Invalid credentials")

@app.post("/promote/{user_id}")
def promote_user(user_id: int, authorization: Optional[str] = Header(None)):
    current = get_current_user(authorization)
    if current not in admins:
        raise HTTPException(status_code=403, detail="Not admin")
    if user_id not in users:
        raise HTTPException(status_code=404, detail="User not found")
    moderators.add(user_id)
    return {"status": "promoted", "user_id": user_id}

@app.post("/{resource}")
def create_resource(resource: str, data: dict, authorization: Optional[str] = Header(None)):
    current = get_current_user(authorization)
    if resource not in resource_types:
        resource_types[resource] = {}
        next_resource_ids[resource] = 1
    res_id = next_resource_ids[resource]
    next_resource_ids[resource] += 1
    data["id"] = res_id
    data["owner"] = current
    resource_types[resource][res_id] = data
    return {"id": res_id, **data}

@app.get("/{resource}/{resource_id}")
def get_resource(resource: str, resource_id: int, authorization: Optional[str] = Header(None)):
    current = get_current_user(authorization)
    if resource not in resource_types:
        raise HTTPException(status_code=404, detail="Resource type not found")
    if resource_id not in resource_types[resource]:
        raise HTTPException(status_code=404, detail="Resource not found")
    return resource_types[resource][resource_id]

