from fastapi import FastAPI, HTTPException, Header
from typing import Optional
import secrets
import hashlib

app = FastAPI()

users = {}
tokens = {}
agents = {}
orders = {}
bookings = {}
next_user_id = 1
next_agent_id = 1
next_order_id = 1
next_booking_id = 1

def get_current_user(authorization: Optional[str] = Header(None)):
    if not authorization:
        raise HTTPException(status_code=401, detail="Missing auth token")
    token = authorization.replace("Bearer ", "")
    for uid, t in tokens.items():
        if t == token:
            return uid
    raise HTTPException(status_code=401, detail="Invalid token")

@app.post("/signup")
def signup(username: str, password: str):
    global next_user_id
    for u in users.values():
        if u["username"] == username:
            raise HTTPException(status_code=400, detail="Username taken")
    uid = next_user_id
    next_user_id += 1
    users[uid] = {"id": uid, "username": username, "password": hashlib.sha256(password.encode()).hexdigest(), "role": "user"}
    return {"id": uid, "username": username}

@app.post("/login")
def login(username: str, password: str):
    for uid, u in users.items():
        if u["username"] == username and u["password"] == hashlib.sha256(password.encode()).hexdigest():
            token = secrets.token_hex(16)
            tokens[uid] = token
            return {"token": token, "user_id": uid}
    raise HTTPException(status_code=401, detail="Invalid credentials")

@app.post("/promote/{user_id}")
def promote(user_id: int, authorization: Optional[str] = Header(None)):
    admin_id = get_current_user(authorization)
    if users.get(admin_id, {}).get("role") != "admin":
        raise HTTPException(status_code=403, detail="Only admins can promote")
    if user_id not in users:
        raise HTTPException(status_code=404, detail="User not found")
    users[user_id]["role"] = "premium_agent"
    return {"message": f"User {user_id} promoted to premium agent"}

@app.post("/agents")
def create_agent(name: str, authorization: Optional[str] = Header(None)):
    user_id = get_current_user(authorization)
    global next_agent_id
    aid = next_agent_id
    next_agent_id += 1
    agents[aid] = {"id": aid, "name": name, "owner_id": user_id}
    return agents[aid]

@app.get("/agents/{agent_id}")
def get_agent(agent_id: int):
    if agent_id not in agents:
        raise HTTPException(status_code=404, detail="Agent not found")
    return agents[agent_id]

@app.post("/orders")
def create_order(destination: str, authorization: Optional[str] = Header(None)):
    user_id = get_current_user(authorization)
    global next_order_id
    oid = next_order_id
    next_order_id += 1
    orders[oid] = {"id": oid, "destination": destination, "user_id": user_id}
    return orders[oid]

@app.get("/orders/{order_id}")
def get_order(order_id: int):
    if order_id not in orders:
        raise HTTPException(status_code=404, detail="Order not found")
    return orders[order_id]

@app.post("/bookings")
def create_booking(details: str, authorization: Optional[str] = Header(None)):
    user_id = get_current_user(authorization)
    global next_booking_id
    bid = next_booking_id
    next_booking_id += 1
    bookings[bid] = {"id": bid, "details": details, "user_id": user_id}
    return bookings[bid]

@app.get("/bookings/{booking_id}")
