from fastapi import FastAPI, HTTPException, Header
from typing import Optional
import random
import string

app = FastAPI()

users = {}
tokens = {}
interests_pool = ["hiking", "reading", "cooking", "gaming", "music", "travel", "photography", "coding", "yoga", "dancing"]
next_user_id = 1
next_suggestion_id = 1
suggestions = {}

def generate_token():
    return ''.join(random.choices(string.ascii_letters + string.digits, k=32))

def get_current_user(authorization: Optional[str] = Header(None)):
    if not authorization:
        raise HTTPException(status_code=401, detail="Missing auth header")
    token = authorization.replace("Bearer ", "")
    if token not in tokens:
        raise HTTPException(status_code=401, detail="Invalid token")
    return tokens[token]

@app.post("/signup")
def signup(username: str, interests: str = ""):
    global next_user_id
    if any(u["username"] == username for u in users.values()):
        raise HTTPException(status_code=400, detail="Username taken")
    user_id = next_user_id
    next_user_id += 1
    interest_list = [i.strip() for i in interests.split(",") if i.strip()] if interests else []
    users[user_id] = {
        "id": user_id,
        "username": username,
        "interests": interest_list,
        "latitude": 0.0,
        "longitude": 0.0
    }
    token = generate_token()
    tokens[token] = user_id
    return {"user_id": user_id, "token": token}

@app.post("/login")
def login(username: str):
    for uid, u in users.items():
        if u["username"] == username:
            token = generate_token()
            tokens[token] = uid
            return {"token": token}
    raise HTTPException(status_code=404, detail="User not found")

@app.get("/users/{user_id}")
def get_user(user_id: int):
    if user_id not in users:
        raise HTTPException(status_code=404, detail="User not found")
    return users[user_id]

@app.post("/users")
def create_user(username: str, interests: str = "", latitude: float = 0.0, longitude: float = 0.0):
    global next_user_id
    if any(u["username"] == username for u in users.values()):
        raise HTTPException(status_code=400, detail="Username taken")
    user_id = next_user_id
    next_user_id += 1
    interest_list = [i.strip() for i in interests.split(",") if i.strip()] if interests else []
    users[user_id] = {
        "id": user_id,
        "username": username,
        "interests": interest_list,
        "latitude": latitude,
        "longitude": longitude
    }
    return users[user_id]

@app.post("/interests")
def add_interest(user_id: int, interest: str, authorization: Optional[str] = Header(None)):
    current_user = get_current_user(authorization)
    if user_id != current_user:
        raise HTTPException(status_code=403, detail="Not your account")
    if user_id not in users:
        raise HTTPException(status_code=404, detail="User not found")
    if interest not in users[user_id]["interests"]:
        users[user_id]["interests"].append(interest)
    return users[user_id]

@app.get("/interests/{interest_id}")
def get_interest(interest_id: int):
    return {"interest": interests_pool[interest_id - 1]} if 0 < interest_id <= len(interests_pool) else HTTPException(404, "Interest not found")

@app.post("/interests")
def create_interest(interest: str):
    if interest in interests_pool:
        raise HTTPException(400, "Interest already exists")
    interests_pool.append(interest)
    return {"id": len(interests_pool), "interest": interest}

@app.get("/matches/suggestions")
def get_suggestions(authorization: Optional[str] = Header(None)):
    current_user = get_current_user(authorization)
    user = users[current_user]
    user_interests = set(user["interests"])

    nearby_users = []
    for uid, u in users.items():
        if uid == current_user:
            continue
        mutual_interests = list(user_interests & set(u["interests"]))

        lat_diff = abs(u["latitude"] - user["latitude"])
        lon_diff = abs(u["longitude"] - user["longitude"])
        is_nearby = lat_diff < 1.0 and lon_diff < 1.0

        if mutual_interests or is_nearby:
            nearby_users.append({
                "user_id": uid,
                "username": u["username"],
                "mutual_interests": mutual_interests,
                "is_nearby": is_nearby
            })

    global next_suggestion_id
    suggestion_id = next_suggestion_id
    next_suggestion_id += 1
    suggestions[suggestion_id] = {
        "id": suggestion_id,
        "user_id": current_user,
        "suggestions": nearby_users
    }
    return suggestions[suggestion_id]

@app.get("/suggestions/{suggestion_id}")
def get_suggestion(suggestion_id: int):
    if suggestion_id not in suggestions:
        raise HTTPException(status_code=404, detail="Suggestion not found")
    return suggestions[suggestion_id]

