from fastapi import FastAPI, HTTPException, Header
from pydantic import BaseModel
from typing import Optional
import secrets
import datetime

app = FastAPI()

# In-memory stores
users = {}
user_id_counter = 1
tokens = {}
events = {}
event_id_counter = 1
orders = {}
order_id_counter = 1

class SignupRequest(BaseModel):
    username: str
    password: str

class LoginRequest(BaseModel):
    username: str
    password: str

class EventCreate(BaseModel):
    name: str
    date: str
    venue: str
    total_tickets: int
    ticket_price: float

class OrderCreate(BaseModel):
    event_id: int
    quantity: int
    token: Optional[str] = None

def get_current_user(authorization: str = Header(None)):
    if not authorization:
        raise HTTPException(status_code=401, detail="Missing authorization header")
    token = authorization.replace("Bearer ", "")
    if token not in tokens:
        raise HTTPException(status_code=401, detail="Invalid token")
    return tokens[token]

@app.post("/signup")
def signup(req: SignupRequest):
    global user_id_counter
    for u in users.values():
        if u["username"] == req.username:
            raise HTTPException(status_code=400, detail="User already exists")
    user_id = user_id_counter
    user_id_counter += 1
    users[user_id] = {"id": user_id, "username": req.username, "password": req.password}
    return {"id": user_id, "username": req.username}

@app.post("/login")
def login(req: LoginRequest):
    for u in users.values():
        if u["username"] == req.username and u["password"] == req.password:
            token = secrets.token_hex(16)
            tokens[token] = u["id"]
            return {"token": token}
    raise HTTPException(status_code=401, detail="Invalid credentials")

@app.post("/events")
def create_event(event: EventCreate, authorization: str = Header(None)):
    get_current_user(authorization)
    global event_id_counter
    event_id = event_id_counter
    event_id_counter += 1
    events[event_id] = {
        "id": event_id,
        "name": event.name,
        "date": event.date,
        "venue": event.venue,
        "total_tickets": event.total_tickets,
        "ticket_price": event.ticket_price,
        "available_tickets": event.total_tickets
    }
    return events[event_id]

@app.get("/events/{event_id}")
def get_event(event_id: int):
    if event_id not in events:
        raise HTTPException(status_code=404, detail="Event not found")
    return events[event_id]

@app.get("/events/upcoming")
def get_upcoming_events():
    today = datetime.date.today().isoformat()
    upcoming = []
    for e in events.values():
        if e["date"] >= today:
            upcoming.append({
                "id": e["id"],
                "name": e["name"],
                "date": e["date"],
                "venue": e["venue"],
                "available_tickets": e["available_tickets"],
                "price_range": {
                    "min": e["ticket_price"],
                    "max": e["ticket_price"]
                }
            })
    return upcoming

@app.post("/orders")
def create_order(order: OrderCreate, authorization: str = Header(None)):
    user_id = get_current_user(authorization)
    if order.event_id not in events:
        raise HTTPException(status_code=404, detail="Event not found")
    event = events[order.event_id]
    if event["available_tickets"] < order.quantity:
        raise HTTPException(status_code=400, detail="Not enough tickets available")
    global order_id_counter
    order_id = order_id_counter
    order_id_counter += 1
    total_price = order.quantity * event["ticket_price"]
    orders[order_id] = {
        "id": order_id,
        "user_id": user_id,
        "event_id": order.event_id,
        "quantity": order.quantity,
        "total_price": total_price
    }
    event["available_tickets"] -= order.quantity
    return orders[order_id]

@app.get("/orders/{order_id}")
def get_order(order_id: int, authorization: str = Header(None)):
    get_current_user(authorization)
    if order_id not in orders:
        raise HTTPException(status_code=404, detail="Order not found")
    return orders[order_id]

@app.get("/users/{user_id}")
def get_user(user_id: int):
    if user_id not in users:
        raise HTTPException(status_code=404, detail="User not found")
    return {"id": users[user_id]["id"], "username": users[user_id]["username"]}

