from fastapi import FastAPI, HTTPException, Header
from pydantic import BaseModel
from typing import Optional
import secrets
import datetime

app = FastAPI()

users = {}
tokens = {}
students = {}
assignments = {}
grades = {}
next_user_id = 1
next_student_id = 1
next_assignment_id = 1
next_grade_id = 1

class SignupRequest(BaseModel):
    username: str
    password: str

class LoginRequest(BaseModel):
    username: str
    password: str

class StudentCreate(BaseModel):
    name: str

class AssignmentCreate(BaseModel):
    title: str
    max_score: float

class GradeCreate(BaseModel):
    student_id: int
    assignment_id: int
    score: float

def get_current_user(authorization: Optional[str] = Header(None)):
    if not authorization:
        raise HTTPException(status_code=401, detail="Missing auth header")
    token = authorization.replace("Bearer ", "")
    if token not in tokens:
        raise HTTPException(status_code=401, detail="Invalid token")
    return tokens[token]

@app.post("/signup")
def signup(req: SignupRequest):
    global next_user_id
    user_id = next_user_id
    next_user_id += 1
    users[user_id] = {"id": user_id, "username": req.username, "password": req.password}
    return {"id": user_id, "username": req.username}

@app.post("/login")
def login(req: LoginRequest):
    for user in users.values():
        if user["username"] == req.username and user["password"] == req.password:
            token = secrets.token_hex(16)
            tokens[token] = user["id"]
            return {"token": token}
    raise HTTPException(status_code=401, detail="Invalid credentials")

@app.post("/students")
def create_student(req: StudentCreate, authorization: Optional[str] = Header(None)):
    get_current_user(authorization)
    global next_student_id
    sid = next_student_id
    next_student_id += 1
    students[sid] = {"id": sid, "name": req.name}
    return students[sid]

@app.get("/students/{student_id}")
def get_student(student_id: int, authorization: Optional[str] = Header(None)):
    get_current_user(authorization)
    if student_id not in students:
        raise HTTPException(status_code=404, detail="Student not found")
    return students[student_id]

@app.post("/assignments")
def create_assignment(req: AssignmentCreate, authorization: Optional[str] = Header(None)):
    get_current_user(authorization)
    global next_assignment_id
    aid = next_assignment_id
    next_assignment_id += 1
    assignments[aid] = {"id": aid, "title": req.title, "max_score": req.max_score}
    return assignments[aid]

@app.get("/assignments/{assignment_id}")
def get_assignment(assignment_id: int, authorization: Optional[str] = Header(None)):
    get_current_user(authorization)
    if assignment_id not in assignments:
        raise HTTPException(status_code=404, detail="Assignment not found")
    return assignments[assignment_id]

@app.post("/grades")
def create_grade(req: GradeCreate, authorization: Optional[str] = Header(None)):
    get_current_user(authorization)
    if req.student_id not in students:
        raise HTTPException(status_code=404, detail="Student not found")
    if req.assignment_id not in assignments:
        raise HTTPException(status_code=404, detail="Assignment not found")
    global next_grade_id
    gid = next_grade_id
    next_grade_id += 1
    grades[gid] = {
        "id": gid,
        "student_id": req.student_id,
        "assignment_id": req.assignment_id,
        "score": req.score,
        "timestamp": datetime.datetime.utcnow().isoformat()
    }
    return grades[gid]

@app.get("/grades/{grade_id}")
def get_grade(grade_id: int, authorization: Optional[str] = Header(None)):
    get_current_user(authorization)
    if grade_id not in grades:
        raise HTTPException(status_code=404, detail="Grade not found")
    return grades[grade_id]

@app.get("/grades/summary")
def grades_summary(authorization: Optional[str] = Header(None)):
    get_current_user(authorization)
    if not grades:
        return {"class_averages": {}, "top_performers": [], "recent_assignments": []}

    student_scores = {}
    assignment_totals = {}
    assignment_counts = {}

    for g in grades.values():
        sid = g["student_id"]
        aid = g["assignment_id"]
        score = g["score"]
        max_score = assignments[aid]["max_score"]
        pct = (score / max_score) * 100

        if sid not in student_scores:
            student_scores[sid] = {"total_pct": 0, "count": 0}
        student_scores[sid]["total_pct"] += pct
        student_scores[sid]["count"] += 1

        if aid not in assignment_totals:
            assignment_totals[aid] = 0
            assignment_counts[aid] = 0
        assignment_totals[aid] += pct
        assignment_counts[aid] += 1

    class_averages = {}
    for aid in assignment_totals:
        class_averages[assignments[aid]["title"]] = round(assignment_totals[aid] / assignment_counts[aid], 2)

    student_avgs = []
    for sid, data in student_scores.items():
        student_avgs.append({"student_id": sid, "name": students[sid]["name"], "average": round(data["total_pct"] / data["count"], 2)})

