app = FastAPI()

users = {}
tokens = {}
students = {}
assignments = {}
grades = {}
next_user_id = 1
next_student_id = 1
next_assignment_id = 1
next_grade_id = 1

class SignupRequest(BaseModel):
    username: str
    password: str

class LoginRequest(BaseModel):
    username: str
    password: str

class StudentCreate(BaseModel):
    name: str

class AssignmentCreate(BaseModel):
    title: str
    max_score: float

class GradeCreate(BaseModel):
