    if req.assignment_id not in assignments:
        raise HTTPException(status_code=404, detail="Assignment not found")
    if students[req.student_id]["owner_id"] != user_id or assignments[req.assignment_id]["owner_id"] != user_id:
        raise HTTPException(status_code=403, detail="Access denied")
    global next_grade_id
    gid = next_grade_id
    next_grade_id += 1
    grades[gid] = {
        "id": gid,
        "student_id": req.student_id,
