    user_id = get_current_user(authorization)
    user_grades = {k: v for k, v in grades.items() if v["owner_id"] == user_id}
    user_students = {k: v for k, v in students.items() if v["owner_id"] == user_id}
    user_assignments = {k: v for k, v in assignments.items() if v["owner_id"] == user_id}

    if not user_grades:
        return {"class_averages": {}, "top_performers": [], "recent_assignments": []}

    student_scores = {}
    assignment_totals = {}
    assignment_counts = {}

    for g in user_grades.values():
        sid = g["student_id"]
        aid = g["assignment_id"]
        score = g["score"]
        max_score = user_assignments[aid]["max_score"]
        pct = (score / max_score) * 100

        if sid not in student_scores:
            student_scores[sid] = {"total_pct": 0, "count": 0}
        student_scores[sid]["total_pct"] += pct
        student_scores[sid]["count"] += 1

        if aid not in assignment_totals:
