            assignment_counts[aid] = 0
        assignment_totals[aid] += pct
        assignment_counts[aid] += 1

    class_averages = {}
    for aid in assignment_totals:
        class_averages[user_assignments[aid]["title"]] = round(assignment_totals[aid] / assignment_counts[aid], 2)

    student_avgs = []
    for sid, data in student_scores.items():
        student_avgs.append({"student_id": sid, "name": user_students[sid]["name"], "average": round(data["total_pct"] / data["count"], 2)})

    student_avgs.sort(key=lambda x: x["average"], reverse=True)
    top_performers = student_avgs[:3] if len(student_avgs) >= 3 else student_avgs

    recent = sorted(user_grades.values(), key=lambda x: x["timestamp"], reverse=True)[:5]
    recent_assignments = []
    for g in recent:
        recent_assignments.append({
            "grade_id": g["id"],
            "student_name": user_students[g["student_id"]]["name"],
            "assignment_title": user_assignments[g["assignment_id"]]["title"],
            "score": g["score"],
            "max_score": user_assignments[g["assignment_id"]]["max_score"],
            "timestamp": g["timestamp"]
        })

    return {
        "class_averages": class_averages,
        "top_performers": top_performers,
        "recent_assignments": recent_assignments
    }

