import sys
import requests

BASE_URL = "http://127.0.0.1:8000"

def test_golden_path():
    session = requests.Session()

    # Signup
    signup_resp = session.post(f"{BASE_URL}/signup", params={"username": "testuser", "password": "testpass123"})
    if signup_resp.status_code != 200:
        return False
    user_data = signup_resp.json()
    if "id" not in user_data or "username" not in user_data:
        return False

    # Login
    login_resp = session.post(f"{BASE_URL}/login", params={"username": "testuser", "password": "testpass123"})
    if login_resp.status_code != 200:
        return False
    token_data = login_resp.json()
    if "token" not in token_data:
        return False
    token = token_data["token"]

    # Create organizer
    headers = {"Authorization": f"Bearer {token}"}
    create_resp = session.post(f"{BASE_URL}/organizers", params={
        "name": "Test Organizer",
        "contact_info": "test@example.com"
    }, headers=headers)
    if create_resp.status_code != 200:
        return False
    org_data = create_resp.json()
    if "id" not in org_data or "name" not in org_data:
        return False
    org_id = org_data["id"]

    # Fetch own organizer
    fetch_resp = session.get(f"{BASE_URL}/organizers/{org_id}", headers=headers)
    if fetch_resp.status_code != 200:
        return False
    fetched_org = fetch_resp.json()
    if fetched_org.get("id") != org_id or fetched_org.get("name") != "Test Organizer":
        return False

    return True

if __name__ == "__main__":
    if test_golden_path():
        print("SPEC_PASS")
        sys.exit(0)
    else:
        print("SPEC_FAIL")
        sys.exit(1)

