            tokens[token] = user["id"]
            return {"token": token}
    raise HTTPException(status_code=401, detail="Invalid credentials")

@app.post("/workouts")
def create_workout(name: str, description: str = "", authorization: Optional[str] = Header(None)):
    user_id = get_current_user(authorization)
    global next_workout_id
    workout_id = next_workout_id
    workouts[workout_id] = {"id": workout_id, "name": name, "description": description, "trainer_id": user_id}
    next_workout_id += 1
    return workouts[workout_id]

