    log_id = next_log_id
    workout_logs[log_id] = {"id": log_id, "workout_id": workout_id, "user_id": user_id, "reps": reps, "sets": sets, "weight": weight}
    next_log_id += 1
    return workout_logs[log_id]

@app.get("/logs/{log_id}")
