from typing import Optional
import secrets

app = FastAPI()

users = {}
tokens = {}
records = {}
record_id_counter = 1

class SignupRequest(BaseModel):
    username: str
    password: str

class LoginRequest(BaseModel):
    username: str
    password: str

class RecordCreate(BaseModel):
    patient_id: int
    content: str

@app.post("/signup")
def signup(req: SignupRequest):
    if req.username in users:
        raise HTTPException(status_code=400, detail="User exists")
    users[req.username] = req.password
    return {"ok": True}

@app.post("/login")
def login(req: LoginRequest):
    if users.get(req.username) != req.password:
        raise HTTPException(status_code=401, detail="Invalid credentials")
    token = secrets.token_hex(16)
    tokens[token] = req.username
    return {"token": token}

@app.post("/records")
def create_record(req: RecordCreate, authorization: Optional[str] = Header(None)):
    if not authorization or not authorization.startswith("Bearer "):
        raise HTTPException(status_code=401, detail="Missing token")
    token = authorization.split(" ")[1]
    if token not in tokens:
        raise HTTPException(status_code=401, detail="Invalid token")
    global record_id_counter
    record_id = record_id_counter
    record_id_counter += 1
    records[record_id] = {"id": record_id, "patient_id": req.patient_id, "content": req.content}
    return records[record_id]

@app.get("/records/{record_id}")
def get_record(record_id: int, authorization: Optional[str] = Header(None)):
    if not authorization or not authorization.startswith("Bearer "):
        raise HTTPException(status_code=401, detail="Missing token")
    token = authorization.split(" ")[1]
    if token not in tokens:
        raise HTTPException(status_code=401, detail="Invalid token")
    if record_id not in records:
        raise HTTPException(status_code=404, detail="Record not found")
    return records[record_id]

