from pydantic import BaseModel
from typing import Optional
import secrets

app = FastAPI()

users = {}
tokens = {}
habits = {}
habit_entries = {}
next_user_id = 1
next_habit_id = 1
next_entry_id = 1

class SignupRequest(BaseModel):
    username: str
    password: str

class LoginRequest(BaseModel):
    username: str
    password: str

class HabitCreate(BaseModel):
    name: str
    description: Optional[str] = None

class EntryCreate(BaseModel):
    habit_id: int
    value: Optional[str] = None

def get_current_user(authorization: str = Header(...)):
    if not authorization.startswith("Bearer "):
        raise HTTPException(status_code=401, detail="Invalid auth header")
    token = authorization[7:]
    if token not in tokens:
        raise HTTPException(status_code=401, detail="Invalid token")
    return tokens[token]

@app.post("/signup")
def signup(req: SignupRequest):
    global next_user_id
    for u in users.values():
        if u["username"] == req.username:
            raise HTTPException(status_code=400, detail="Username already exists")
    user_id = next_user_id
    next_user_id += 1
    users[user_id] = {"id": user_id, "username": req.username, "password": req.password}
    return {"id": user_id, "username": req.username}

@app.post("/login")
def login(req: LoginRequest):
    for u in users.values():
        if u["username"] == req.username and u["password"] == req.password:
            token = secrets.token_hex(32)
            tokens[token] = u["id"]
            return {"token": token}
    raise HTTPException(status_code=401, detail="Invalid credentials")

@app.post("/habits")
def create_habit(habit: HabitCreate, authorization: str = Header(...)):
    user_id = get_current_user(authorization)
    global next_habit_id
    habit_id = next_habit_id
    next_habit_id += 1
    habits[habit_id] = {"id": habit_id, "name": habit.name, "description": habit.description, "user_id": user_id}
    return habits[habit_id]

@app.get("/habits/{habit_id}")
def get_habit(habit_id: int, authorization: str = Header(...)):
    user_id = get_current_user(authorization)
    if habit_id not in habits:
        raise HTTPException(status_code=404, detail="Habit not found")
    return habits[habit_id]

@app.post("/entries")
def create_entry(entry: EntryCreate, authorization: str = Header(...)):
    user_id = get_current_user(authorization)
    if entry.habit_id not in habits:
        raise HTTPException(status_code=404, detail="Habit not found")
    global next_entry_id
    entry_id = next_entry_id
    next_entry_id += 1
    habit_entries[entry_id] = {"id": entry_id, "habit_id": entry.habit_id, "value": entry.value, "user_id": user_id}
    return habit_entries[entry_id]

