from fastapi import FastAPI, HTTPException, Header
from typing import Optional
import secrets

app = FastAPI()

users = {}
tokens = {}
playlists = {}
playlist_songs = {}
next_user_id = 1
next_playlist_id = 1
next_song_id = 1

def get_current_user(authorization: Optional[str] = Header(None)):
    if not authorization:
        raise HTTPException(status_code=401, detail="Missing auth token")
    token = authorization.replace("Bearer ", "")
    user_id = tokens.get(token)
    if not user_id:
        raise HTTPException(status_code=401, detail="Invalid token")
    return user_id

@app.post("/signup")
def signup(username: str, password: str):
    global next_user_id
    user_id = next_user_id
    users[user_id] = {"username": username, "password": password}
    next_user_id += 1
    return {"user_id": user_id}

@app.post("/login")
def login(username: str, password: str):
    for uid, user in users.items():
        if user["username"] == username and user["password"] == password:
            token = secrets.token_hex(16)
            tokens[token] = uid
            return {"token": token}
    raise HTTPException(status_code=401, detail="Invalid credentials")

@app.post("/playlists")
def create_playlist(name: str, authorization: Optional[str] = Header(None)):
    user_id = get_current_user(authorization)
    global next_playlist_id
    playlist_id = next_playlist_id
    playlists[playlist_id] = {"id": playlist_id, "name": name, "creator_id": user_id}
    playlist_songs[playlist_id] = []
    next_playlist_id += 1
    return {"playlist_id": playlist_id}

@app.get("/playlists/{playlist_id}")
def get_playlist(playlist_id: int, authorization: Optional[str] = Header(None)):
    get_current_user(authorization)
    playlist = playlists.get(playlist_id)
    if not playlist:
        raise HTTPException(status_code=404, detail="Playlist not found")
    return playlist

@app.post("/playlists/{playlist_id}/songs")
def add_song_to_playlist(playlist_id: int, title: str, artist: str, authorization: Optional[str] = Header(None)):
    user_id = get_current_user(authorization)
    playlist = playlists.get(playlist_id)
    if not playlist:
        raise HTTPException(status_code=404, detail="Playlist not found")
    if playlist["creator_id"] != user_id:
        raise HTTPException(status_code=403, detail="Only the creator can add songs")
    global next_song_id
    song_id = next_song_id
    playlist_songs[playlist_id].append({"id": song_id, "title": title, "artist": artist})
    next_song_id += 1
    return {"song_id": song_id}

@app.get("/playlists/{playlist_id}/songs")
def get_playlist_songs(playlist_id: int, authorization: Optional[str] = Header(None)):
    get_current_user(authorization)
    if playlist_id not in playlists:
        raise HTTPException(status_code=404, detail="Playlist not found")
    return playlist_songs.get(playlist_id, [])

