app = FastAPI()

users = {}
tokens = {}
grades = {}
courses = {}
user_ids = 1
grade_ids = 1
course_ids = 1

class SignupRequest(BaseModel):
    username: str
    password: str
    role: str = "student"

class LoginRequest(BaseModel):
    username: str
    password: str

class GradeCreate(BaseModel):
    student_id: int
    course_id: int
    grade: float

class CourseCreate(BaseModel):
    name: str

def get_current_user(authorization: str = Header(None)):
    if not authorization:
        raise HTTPException(status_code=401, detail="No auth header")
    token = authorization.replace("Bearer ", "")
    if token not in tokens:
        raise HTTPException(status_code=401, detail="Invalid token")
    return tokens[token]

@app.post("/signup")
def signup(req: SignupRequest):
    global user_ids
    for u in users.values():
        if u["username"] == req.username:
            raise HTTPException(status_code=400, detail="Username exists")
    user_id = user_ids
    user_ids += 1
    users[user_id] = {"id": user_id, "username": req.username, "password": req.password, "role": req.role}
    return {"id": user_id, "username": req.username, "role": req.role}

@app.post("/login")
def login(req: LoginRequest):
    for u in users.values():
        if u["username"] == req.username and u["password"] == req.password:
            token = secrets.token_hex(16)
            tokens[token] = u
            return {"token": token}
    raise HTTPException(status_code=401, detail="Invalid credentials")

@app.post("/courses")
def create_course(req: CourseCreate, authorization: str = Header(None)):
    user = get_current_user(authorization)
    if user["role"] != "teacher":
        raise HTTPException(status_code=403, detail="Only teachers can create courses")
    global course_ids
    course_id = course_ids
    course_ids += 1
    courses[course_id] = {"id": course_id, "name": req.name, "teacher_id": user["id"]}
    return courses[course_id]

@app.get("/courses/{course_id}")
def get_course(course_id: int):
    if course_id not in courses:
        raise HTTPException(status_code=404, detail="Course not found")
    return courses[course_id]

@app.post("/grades")
def create_grade(req: GradeCreate, authorization: str = Header(None)):
    user = get_current_user(authorization)
    if user["role"] != "teacher":
        raise HTTPException(status_code=403, detail="Only teachers can post grades")
    if req.course_id not in courses:
        raise HTTPException(status_code=404, detail="Course not found")
    if req.student_id not in users:
        raise HTTPException(status_code=404, detail="Student not found")
    global grade_ids
    grade_id = grade_ids
    grade_ids += 1
    grades[grade_id] = {"id": grade_id, "student_id": req.student_id, "course_id": req.course_id, "grade": req.grade}
    return grades[grade_id]

@app.get("/grades/{grade_id}")
def get_grade(grade_id: int):
    if grade_id not in grades:
        raise HTTPException(status_code=404, detail="Grade not found")
    return grades[grade_id]

@app.get("/grades")
def list_my_grades(authorization: str = Header(None)):
    user = get_current_user(authorization)
    if user["role"] != "student":
        raise HTTPException(status_code=403, detail="Only students can view their grades")
    student_grades = [g for g in grades.values() if g["student_id"] == user["id"]]
    return student_grades

