from pydantic import BaseModel
from typing import Optional
import secrets

app = FastAPI()

users = {}
tokens = {}
messages = {}
user_id_counter = 1
message_id_counter = 1

class SignupRequest(BaseModel):
    username: str
    password: str
    is_admin: bool = False

class LoginRequest(BaseModel):
    username: str
    password: str

class MessageCreate(BaseModel):
    content: str

def get_current_user(authorization: Optional[str] = Header(None)):
    if not authorization:
        raise HTTPException(status_code=401, detail="Missing auth header")
    token = authorization.replace("Bearer ", "")
    if token not in tokens:
        raise HTTPException(status_code=401, detail="Invalid token")
    return tokens[token]

@app.post("/signup")
def signup(req: SignupRequest):
    global user_id_counter
    for u in users.values():
        if u["username"] == req.username:
            raise HTTPException(status_code=400, detail="Username already exists")
    user_id = user_id_counter
    user_id_counter += 1
    users[user_id] = {
        "id": user_id,
        "username": req.username,
        "password": req.password,
        "is_admin": req.is_admin
    }
    token = secrets.token_hex(16)
    tokens[token] = user_id
    return {"token": token, "user_id": user_id}

@app.post("/login")
def login(req: LoginRequest):
    for uid, u in users.items():
        if u["username"] == req.username and u["password"] == req.password:
            token = secrets.token_hex(16)
            tokens[token] = uid
            return {"token": token, "user_id": uid}
    raise HTTPException(status_code=401, detail="Invalid credentials")

@app.post("/messages")
def create_message(msg: MessageCreate, authorization: Optional[str] = Header(None)):
    global message_id_counter
    user_id = get_current_user(authorization)
    message_id = message_id_counter
    message_id_counter += 1
    messages[message_id] = {
        "id": message_id,
        "content": msg.content,
        "user_id": user_id
    }
    return messages[message_id]

@app.get("/messages/{message_id}")
def get_message(message_id: int, authorization: Optional[str] = Header(None)):
    get_current_user(authorization)
    if message_id not in messages:
        raise HTTPException(status_code=404, detail="Message not found")
    return messages[message_id]

@app.delete("/messages/{message_id}")
def delete_message(message_id: int, authorization: Optional[str] = Header(None)):
    user_id = get_current_user(authorization)
    user = users[user_id]
    if not user["is_admin"]:
        raise HTTPException(status_code=403, detail="Only admins can delete messages")
    if message_id not in messages:
        raise HTTPException(status_code=404, detail="Message not found")
    del messages[message_id]
    return {"ok": True}

