    tokens[token] = users[username]["id"]
    return {"token": token}

def get_current_user(authorization: Optional[str] = Header(None)):
    if not authorization:
        raise HTTPException(status_code=401, detail="Missing token")
    token = authorization.replace("Bearer ", "")
    if token not in tokens:
        raise HTTPException(status_code=401, detail="Invalid token")
    return tokens[token]

@app.post("/notes")
def create_note(title: str, content: str, authorization: Optional[str] = Header(None)):
    user_id = get_current_user(authorization)
    global next_note_id
    note_id = next_note_id
    next_note_id += 1
    notes[note_id] = {"id": note_id, "title": title, "content": content, "user_id": user_id}
    return notes[note_id]

@app.get("/notes/{note_id}")
def get_note(note_id: int, authorization: Optional[str] = Header(None)):
    user_id = get_current_user(authorization)
    if note_id not in notes:
        raise HTTPException(status_code=404, detail="Note not found")
    if notes[note_id]["user_id"] != user_id:
        raise HTTPException(status_code=403, detail="Access denied")
    return notes[note_id]

